INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 0.0, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 0.0, 24001, 401, 2, "アヤネ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 2.21, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 0.0, 24002, 402, 1, "アヤネ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 0.0, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 0.0, 24003, 403, 2, "アヤネ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 1.99, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 0.0, 24004, 701, 2, "アサヒ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 2.21, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 0.0, 24005, 702, 1, "アサヒ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 3.33, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 0.0, 24006, 703, 2, "アサヒ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 0.0, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 0.0, 24007, 801, 2, "部員３", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 2.68, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 0.0, 24008, 802, 1, "部員３", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 0.0, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 0.0, 24009, 803, 2, "部員３", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "やった！", 0.0, 24010, 501, 1, "", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "勝ったよ！", 0.0, 24011, 502, 1, "", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "いい調子！", 0.0, 24012, 503, 1, "", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 5.33, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 0.0, 24013, 111, 6, "ミサト", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 6.85, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 0.0, 24014, 112, 1, "ミサト", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 3.0, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 0.0, 24015, 113, 1, "ミサト", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192401, 6.11, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 0.0, 24016, 611, 1, "ダイチ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192401, 6.75, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 0.0, 24017, 612, 1, "ダイチ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192401, 0.0, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 0.0, 24018, 613, 2, "ダイチ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113401, 4.52, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 0.0, 24019, 211, 2, "ハツネ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113401, 3.89, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 0.0, 24020, 212, 2, "ハツネ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113401, 13.49, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 0.0, 24021, 213, 1, "ハツネ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (106501, 3.17, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 0.0, 24022, 311, 1, "カヤ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (106501, 4.42, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 0.0, 24023, 312, 1, "カヤ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (106501, 2.89, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 0.0, 24024, 313, 6, "カヤ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 3.71, 24, "2030/12/17 14:59:59", 3, "2020/07/31 12:00:00", "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 0.0, 24025, 421, 4, "アヤネ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 5.1, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 0.0, 24026, 721, 2, "アサヒ", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 4.34, 24, "2030/12/17 14:59:59", 3, "2020/07/31 12:00:00", "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 0.0, 24027, 821, 1, "部員３", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "いい勝負だったよ\nまたやろうね", 0.0, 24028, 521, 1, "", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 5.62, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", -360.0, 24029, 101, 1, "ミサト", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 9.58, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", -360.0, 24030, 102, 1, "ミサト", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 0.0, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", -360.0, 24031, 103, 2, "ミサト", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 9.13, 24, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", -360.0, 24032, 104, 2, "ミサト", 0.0, 10046);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 8.27, 24, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", -360.0, 24033, 105, 1, "ミサト", 0.0, 10046);
